import{_ as t,o as a,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Attribution (New)","description":"","frontmatter":{"title":"Attribution (New)","slug":"attribution-page-new"},"headers":[],"relativePath":"account-hub/attribution-page-new.md","filePath":"account-hub/attribution-page-new.md"}'),o={name:"account-hub/attribution-page-new.md"};function r(s,e,d,c,l,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Attribution page is where you configure how Branch attributes user sessions, tracks organic traffic, and measures conversion events.</p><p>Use this page to manage:</p><ul><li><a href="./predictive-aggregate-measurement-index.html">Predictive Aggregate Measurement (PAM)</a></li><li><a href="./seo-app-attribution.html">SEO and AIO App Attribution</a></li><li><a href="./attribution-windows.html">Attribution windows</a></li></ul><p>You can access this page by navigating to <strong>Configuration</strong> → <a href="https://branchdocs.app.link/attribution" target="_blank" rel="noreferrer"><strong>Attribution</strong></a> in Branch.</p><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this page yet?</p><p>The Attribution page is part of the <a href="./new-branch-overview.html">new Branch</a> experience. This page is being rolled out to customers in phases through 2026. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p></div><h2 id="configure-settings" tabindex="-1">Configure settings <a class="header-anchor" href="#configure-settings" aria-label="Permalink to &quot;Configure settings&quot;">​</a></h2><p>The Attribution page includes the following configuration options:</p><h3 id="pam" tabindex="-1">PAM <a class="header-anchor" href="#pam" aria-label="Permalink to &quot;PAM&quot;">​</a></h3><p>Predictive Aggregate Measurement (PAM) is Branch&#39;s attribution modeling solution designed to expand mobile attribution coverage. While solutions like SKAdNetwork (SKAN) provide some measurement, they&#39;re highly limited. PAM unlocks additional insights for users who would otherwise only show up in aggregated reports or be marked as <code>Unattributed</code> entirely. PAM can be leveraged alongside SKAN and AdAttributionKit.</p><p>Toggle the <strong>PAM switch</strong> on the Attribution page to enable this feature for your account.</p><p>For detailed information about PAM, visit the <a href="./predictive-aggregate-measurement.html">PAM Overview</a> and <a href="./predictive-aggregate-measurement-data-reference.html">PAM Data Reference</a> articles.</p><h3 id="seo-and-aio" tabindex="-1">SEO and AIO <a class="header-anchor" href="#seo-and-aio" aria-label="Permalink to &quot;SEO and AIO&quot;">​</a></h3><p>SEO App Attribution tracks and attributes organic traffic from search engines. When users arrive from Google, Bing, Yahoo, or <a href="./seo-app-attribution.html#channel">other search engines</a>, Branch identifies the source and attributes the session to the <code>organic search</code> channel.</p><p>AIO App Attribution tracks and attribution organic traffic from AI chat agents. When users arrive from ChatGPT, Claude, Gemini, Copilot, or Perplexity, Branch identifies the source and attributions the session to the <code>organic chat agent</code> channel.</p><p>In the <strong>Type to add Search Engine Result Page (SERP) Domains</strong> field, list each domain you want to enable SEO and AIO App Attribution for. Wildcard characters are not supported, so you must specify the exact domain, like <code>https://www.branch.io</code>.</p><p>Before you can use SEO and AIO App Attribution, your development team must implement the Branch SDK and configure Universal Links and App Links. See the <a href="./seo-aio-implementation.html">SEO and AIO implementation documentation</a> for technical setup details.</p><p>For more information about SEO and AIO App Attribution, including analytics and troubleshooting, visit the general <a href="./seo-app-attribution.html">SEO and AIO App Attribution documentation</a>.</p><h3 id="attribution-windows" tabindex="-1">Attribution windows <a class="header-anchor" href="#attribution-windows" aria-label="Permalink to &quot;Attribution windows&quot;">​</a></h3><p>Attribution windows define the time periods during which Branch can attribute conversion events back to a specific touch point (click or impression). These windows control the maximum time allowed between a user&#39;s interaction with your marketing and the resulting downstream event.</p><p>The <strong>Attribution Windows</strong> section of the Attribution page displays a table with the following attribution types:</p><table tabindex="0"><thead><tr><th>Attribution type</th><th>Description</th></tr></thead><tbody><tr><td><code>click to start session</code></td><td>Time between a click and an open or web session start (default: 1 day)</td></tr><tr><td><code>click to install</code></td><td>Time between a click and an install or reinstall (default: 7 days)</td></tr><tr><td><code>click to conversion event</code></td><td>Time between a click and a conversion event. Conversion events include <a href="./track-branch-events.html#track-commerce-events">Commerce Events</a> (e.g. <code>purchase</code>, <code>add_to_cart</code>), all <a href="./track-branch-events.html#custom-events">Custom Events</a>, and all <a href="./branch-event-ontology.html">view-based Branch Events</a> like <code>pageview</code> (default: 30 days)</td></tr><tr><td><code>impression to start session</code></td><td>Time between an ad <code>impression</code> and an <code>open</code> or <code>web_session_start</code> (default: 1 day)</td></tr><tr><td><code>impression to install</code></td><td>Time between an ad <code>impression</code> and an <code>install</code> or <code>reinstall</code> (default: 1 day)</td></tr><tr><td><code>impression to conversion event</code></td><td>Time between an ad <code>impression</code> and a conversion event (default: 7 days)</td></tr><tr><td><code>deep linking duration</code></td><td>Maximum time between a <code>click</code> and a user being deep linked (default: 120 minutes)</td></tr><tr><td><code>re-engagement inactivity</code></td><td>Defines the period between two events that a user must be inactive to define the later event as a re-engagement (default: 7 days)</td></tr><tr><td><code>household measurement window</code></td><td>Time between a household device&#39;s ad engagement and an <code>install</code>, <code>open</code>, or <code>web_session_start</code> (default: 2 days)</td></tr></tbody></table><p>.png)</p><h4 id="adjust-attribution-windows" tabindex="-1">Adjust attribution windows <a class="header-anchor" href="#adjust-attribution-windows" aria-label="Permalink to &quot;Adjust attribution windows&quot;">​</a></h4><p>To adjust your attribution windows, select the window value you want to change in the table and enter your desired value. You can define windows as small as 0.0007 days (approximately 1 minute) or as long as 90 days, depending on the attribution type.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Changes to attribution windows settings apply to future attributions only. Allow several minutes for changes to persist through Branch&#39;s system.</p></div><p>For more detailed information about attribution windows, including organization and app-level inheritance, visit the <a href="./attribution-windows.html">Attribution Windows documentation</a>.</p><h4 id="important-notes" tabindex="-1">Important notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important notes&quot;">​</a></h4><p>Reference the following notes when adjusting your attribution windows:</p><ul><li><p><code>deep linking duration</code> includes anyone clicking a Branch Link or being automatically redirected to the app through a Branch Web SDK call. This setting also covers the maximum length of time allowed for probabilistic modeling. Hence changing this value will also change the length of time allowed to use probabilistic modeling for attribution.</p></li><li><p><code>click to ...</code> attribution types refer to events that occur after someone clicks a Branch Link.</p><ul><li>For example, if someone clicks and installs from a Branch Link, and comes back 10 days later to purchase (assuming <code>click to conversion event</code> window is set to greater than 10 days), Branch would count that as an attributed conversion.</li></ul></li><li><p><code>impression to ...</code> attribution types refer to events that occur after someone views a <a href="https://help.branch.io/marketer-hub/docs/ads-advanced-configuration#viewthrough-attribution-vta-with-impression-pixels" target="_blank" rel="noreferrer">Branch Impression Tracking Link</a>.</p></li><li><p><code>re-engagement inactivity</code> is used in re-engagement cohort analysis but not activity analysis.</p></li></ul><h2 id="save-changes" tabindex="-1">Save changes <a class="header-anchor" href="#save-changes" aria-label="Permalink to &quot;Save changes&quot;">​</a></h2><p>After making any changes to your attribution settings, select the <strong>Save Changes</strong> button at the top of the page to apply your updates.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Changes to attribution settings can significantly impact how Branch attributes user sessions and conversion events. Review your changes carefully before saving.</p></div>',33)])])}const g=t(o,[["render",r]]);export{p as __pageData,g as default};
